const response = $input.first().json;

try {
  const agentResponse = JSON.parse(response.AGENT_RESPONSE || response.agent_response || '{}');
  const messages = agentResponse.messages || [];
  const lastMessage = messages[messages.length - 1] || {};
  const content = lastMessage.content || '';

  let parsed = {};
  try {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      parsed = JSON.parse(jsonMatch[0]);
    }
  } catch (e) {
    parsed = { raw_response: content };
  }

  return {
    json: {
      reporter_name: parsed.reporter_name || null,
      department: parsed.department || null,
      category: parsed.category || 'OTHER',
      priority: parsed.priority || 'MEDIUM',
      summary: parsed.summary || 'No summary',
      details: parsed.details || [],
      matched_asset_id: parsed.matched_asset_id || null,
      can_resolve: parsed.priority !== 'HIGH',
      original_message: $('Webhook').first().json.body?.message || '',
      user_id: $('Webhook').first().json.body?.user_id || '',
      channel_id: $('Webhook').first().json.body?.channel_id || '',
      raw_response: content
    }
  };
} catch (e) {
  return {
    json: {
      error: e.message,
      can_resolve: false,
      original_message: $('Webhook').first().json.body?.message || '',
      category: 'OTHER',
      priority: 'HIGH',
      summary: 'Parse error - escalating'
    }
  };
}

